38	use dialect_mir::attributes::MirCastKindAttr;
39	use dialect_mir::ops::{MirAllocaOp, MirCastOp, MirLoadOp, MirStoreOp};
40	use dialect_mir::types::{MirPtrType, address_space};
41	use pliron::basic_block::BasicBlock;
42	use pliron::context::{Context, Ptr};
43	use pliron::op::Op;
44	use pliron::operation::Operation;
45	use pliron::r#type::{TypeHandle, Typed};
46	use pliron::value::Value;
47	use rustc_public::CrateDef;
48	use rustc_public::mir;
49	use rustc_public::mir::alloc::GlobalAlloc;
50	use rustc_public::ty::{ConstantKind, RigidTy, TyKind};
51	
52	/// Maps MIR locals to their alloca slots.
53	///
54	/// # Invariants
55	///
56	/// - `slots.len() == num_locals` after construction.
57	/// - Each `Some(slot)` entry carries a value whose type is [`MirPtrType`];
58	///   the pointee is the local's Pliron-IR type.
59	/// - ZST locals (and the unit return slot) remain `None` in `slots`.
60	pub struct ValueMap {
61	    slots: Vec<Option<Value>>,
62	}
63	
64	impl ValueMap {
65	    /// Creates a new map with capacity for the given number of MIR locals.
66	    pub fn new(num_locals: usize) -> Self {
67	        Self {
68	            slots: vec![None; num_locals],
69	        }
70	    }
71	
72	    /// Return the alloca pointer backing `local`, or `None` if the local is
73	    /// ZST / has not been given a slot.
74	    pub fn get_slot(&self, local: mir::Local) -> Option<Value> {
75	        let idx: usize = local;
76	        self.slots.get(idx).copied().flatten()
77	    }
78	
79	    /// Record the alloca pointer for `local`. Expected to be called once per
80	    /// non-ZST local during body setup in [`super::body::translate_body`].
81	    pub fn set_slot(&mut self, local: mir::Local, slot: Value) {
82	        let idx: usize = local;
83	        if idx < self.slots.len() {
84	            self.slots[idx] = Some(slot);
85	        }
86	    }
87	
88	    /// Emit a `mir.alloca` for `elem_ty` and insert it into `block`.
89	    ///
90	    /// The result pointer lives in the generic address space and is marked
91	    /// mutable; the alloca's pointee carries the allocated element type. If
92	    /// `prev_op` is provided, the op is linked immediately after it; otherwise
93	    /// it is inserted at the front of `block`.
94	    ///
95	    /// Returns the inserted op and its result pointer value.
96	    pub fn emit_alloca(
97	        ctx: &mut Context,
98	        elem_ty: TypeHandle,
99	        block: Ptr<BasicBlock>,
100	        prev_op: Option<Ptr<Operation>>,
101	    ) -> (Ptr<Operation>, Value) {
102	        let ptr_ty = MirPtrType::get_generic(ctx, elem_ty, /* is_mutable */ true);
103	        let op = Operation::new(
104	            ctx,
105	            MirAllocaOp::get_concrete_op_info(),
106	            vec![ptr_ty.into()],
107	            vec![],
108	            vec![],
109	            0,
110	        );
111	        insert_at(ctx, op, block, prev_op);
112	        let result = op.deref(ctx).get_result(0);
113	        (op, result)
114	    }
115	
116	    /// Emit `mir.load` from `local`'s slot. Returns `None` for ZST / unset
117	    /// locals.
118	    pub fn load_local(
119	        &self,
120	        ctx: &mut Context,
121	        local: mir::Local,
122	        block: Ptr<BasicBlock>,
123	        prev_op: Option<Ptr<Operation>>,
124	    ) -> Option<(Ptr<Operation>, Value)> {
125	        let slot = self.get_slot(local)?;
126	        let elem_ty = slot_pointee(ctx, slot);
127	        let op = Operation::new(
128	            ctx,
129	            MirLoadOp::get_concrete_op_info(),
130	            vec![elem_ty],
131	            vec![slot],
132	            vec![],
133	            0,
134	        );
135	        insert_at(ctx, op, block, prev_op);
136	        let result = op.deref(ctx).get_result(0);
137	        Some((op, result))
138	    }
139	
140	    /// Emit `mir.store` of `value` into `local`'s slot. Returns `None` for ZST
141	    /// / unset locals.
142	    ///
143	    /// When `value` is a pointer whose type differs from the slot's declared
144	    /// pointee (mutability, address space, or underlying pointee shape), a
145	    /// `mir.cast <PtrToPtr>` is inserted automatically. This bridges the
146	    /// common case where an rvalue produces a pointer in a concrete address
147	    /// space (e.g. `shared_alloc` returning `*mut T addrspace(3)`) while the
148	    /// local's Rust-declared type translates to a generic-addrspace pointer
149	    /// (e.g. `*mut SharedArray<T, N>` -> `*mut ()`). All pointers have the
150	    /// same runtime layout after lowering, so the cast is free.
151	    pub fn store_local(
152	        &self,
153	        ctx: &mut Context,
154	        local: mir::Local,
155	        value: Value,
156	        block: Ptr<BasicBlock>,
157	        prev_op: Option<Ptr<Operation>>,
158	    ) -> Option<Ptr<Operation>> {
159	        let slot = self.get_slot(local)?;
160	        let slot_elem_ty = slot_pointee(ctx, slot);
161	        let (value, prev_op) = maybe_ptr_coerce(ctx, value, slot_elem_ty, block, prev_op);
162	        let op = Operation::new(
163	            ctx,
164	            MirStoreOp::get_concrete_op_info(),
165	            vec![],
166	            vec![slot, value],
167	            vec![],
168	            0,
169	        );
170	        insert_at(ctx, op, block, prev_op);
171	        Some(op)
172	    }
173	}
174	
175	/// If `value` is a pointer whose type differs from `target_ty` (also a
176	/// pointer), emit a `mir.cast <PtrToPtr>` that converts it. Returns the (new)
177	/// value and the (new) anchor op. Otherwise this is a no-op.
178	pub(crate) fn maybe_ptr_coerce(
179	    ctx: &mut Context,
180	    value: Value,
181	    target_ty: TypeHandle,
182	    block: Ptr<BasicBlock>,
183	    prev_op: Option<Ptr<Operation>>,
184	) -> (Value, Option<Ptr<Operation>>) {
185	    let value_ty = value.get_type(ctx);
186	    if value_ty == target_ty {
187	        return (value, prev_op);
188	    }
189	
190	    // Only auto-insert a PtrToPtr cast when both sides are already pointer
191	    // types; anything else is a genuine translation mismatch and should be
192	    // surfaced by the verifier, not papered over here.
193	    let value_is_ptr = value_ty.deref(ctx).downcast_ref::<MirPtrType>().is_some();
194	    let target_is_ptr = target_ty.deref(ctx).downcast_ref::<MirPtrType>().is_some();
195	    if !(value_is_ptr && target_is_ptr) {
196	        return (value, prev_op);
197	    }
198	
199	    let cast_op = Operation::new(
200	        ctx,
201	        MirCastOp::get_concrete_op_info(),
202	        vec![target_ty],
203	        vec![value],
204	        vec![],
205	        0,
206	    );
207	    insert_at(ctx, cast_op, block, prev_op);
208	    MirCastOp::new(cast_op).set_attr_cast_kind(ctx, MirCastKindAttr::PtrToPtr);
209	    let cast_value = cast_op.deref(ctx).get_result(0);
210	    (cast_value, Some(cast_op))
211	}
212	
213	/// Recover the pointee (element) type of a slot value. Panics if the value is
214	/// not a `MirPtrType`; this invariant is established when a slot is recorded
215	/// via [`ValueMap::set_slot`] after an [`ValueMap::emit_alloca`] call.
216	fn slot_pointee(ctx: &Context, slot: Value) -> TypeHandle {
217	    let ptr_ty = slot.get_type(ctx);
218	    ptr_ty
219	        .deref(ctx)
220	        .downcast_ref::<MirPtrType>()
221	        .expect("ValueMap slot must carry a MirPtrType value")
222	        .pointee
223	}
224	
225	/// Insert `op` after `prev_op` if provided, else at the front of `block`.
226	fn insert_at(
227	    ctx: &mut Context,
228	    op: Ptr<Operation>,
229	    block: Ptr<BasicBlock>,
230	    prev_op: Option<Ptr<Operation>>,
231	) {
232	    match prev_op {
233	        Some(prev) => op.insert_after(ctx, prev),
234	        None => op.insert_at_front(block, ctx),
235	    }
236	}
237	
238	// =============================================================================
239	// Slot address-space inference
240	// =============================================================================
241	
242	/// Per-local inferred address space for the alloca slot's *pointee* type.
243	///
244	/// Only meaningful when the local's translated type is itself a pointer
245	/// (`MirPtrType`). For non-pointer locals this state is computed but never
246	/// consulted — the slot pointee has no addrspace field to override.
247	///
248	/// The lattice is monotone (`Uninit → Known(n) → Generic`, never backwards);
249	/// this guarantees the fixed-point in [`SlotAddrSpaceMap::analyze`] terminates.
250	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
251	enum SlotAddrSpace {
252	    /// No classified writes observed yet. The slot will fall back to the
253	    /// Rust-declared address space in [`SlotAddrSpaceMap::effective`]. This
254	    /// is the critical "trust the type" state: if the classifier has
255	    /// nothing confident to say, we defer to Rust's typed addrspace rather
256	    /// than demoting to generic.
257	    Uninit,
258	    /// Every classified write so far produced a pointer in this address
259	    /// space; the slot can safely be typed to match.
260	    Known(u32),
261	    /// Classified writes from multiple, disagreeing address spaces were
262	    /// observed. The slot must stay generic (`addrspace(0)`) so
263	    /// `maybe_ptr_coerce` can cast every store site to match.
264	    Generic,
265	}
266	
267	impl SlotAddrSpace {
268	    /// Monotone join of two observations on the same slot.
269	    ///
270	    /// - `Uninit` is the identity (no observation ≡ no change).
271	    /// - Two `Known(n)` that agree stay `Known(n)`.
272	    /// - Two disagreeing `Known(_)` collapse to `Generic`.
273	    /// - `Generic` is the absorbing element (once demoted, stay demoted).
274	    fn merge(self, other: SlotAddrSpace) -> SlotAddrSpace {
275	        use SlotAddrSpace::*;
276	        match (self, other) {
277	            (Uninit, x) | (x, Uninit) => x,
278	            (Generic, _) | (_, Generic) => Generic,
279	            (Known(a), Known(b)) if a == b => Known(a),
280	            (Known(_), Known(_)) => Generic,
281	        }
282	    }
283	}
284	
285	/// Result of classifying a single write's right-hand side.
286	///
287	/// Fed into [`SlotAddrSpace::merge`] by the analyzer driver.
288	#[derive(Debug, Clone, Copy)]
289	enum WriteClass {
290	    /// We are confident this write produced a pointer in this address space.
291	    /// Merging promotes an `Uninit` slot to `Known(n)` and disagreeing
292	    /// `Known(_)` slots to `Generic`.
293	    Classified(u32),
294	    /// The write produced something we deliberately don't reason about
295	    /// (aggregates, arithmetic, casts, complex projections, `Ref`/`AddressOf`,
296	    /// arbitrary function returns not in the intrinsic whitelist, …).
297	    ///
298	    /// Crucially this does **not** demote the slot: we already trust
299	    /// Rust's declared addrspace as the fallback (see [`SlotAddrSpace::Uninit`]),
300	    /// so an unclassified write is equivalent to no observation. If the slot
301	    /// was already `Known(n)` from a prior classified write, it stays
302	    /// `Known(n)`. Demoting would be catastrophic for locals whose declared
303	    /// type is a non-generic addrspace (e.g. `&mut SharedArray<_>` reborrows
304	    /// in `tiled_gemm`).
305	    Unclassified,
306	    /// The write is `_y = _x`-style propagation from a local whose state is
307	    /// still [`SlotAddrSpace::Uninit`]. That's a timing artefact of the
308	    /// fixed-point iteration, not a genuine "unknown" — we skip this write
309	    /// and re-examine it on the next iteration, by which point the source
310	    /// local will have either classified or stayed `Uninit`.
311	    Pending,
312	}
313	
314	/// Per-local result of the address-space pre-scan.
315	///
316	/// Indexed by [`mir::Local`]; `body::emit_entry_allocas` consults this once
317	/// per non-ZST local to decide the alloca pointee's addrspace.
318	pub struct SlotAddrSpaceMap {
319	    classes: Vec<SlotAddrSpace>,
320	}
321	
322	impl SlotAddrSpaceMap {
323	    /// Infer per-local slot pointee address spaces by pre-scanning `body`.
324	    ///
325	    /// Each iteration walks every statement and every `Call` terminator,
326	    /// classifies the RHS, and merges classified observations into the
327	    /// destination local's state. Only `Classified(_)` observations change
328	    /// state; `Unclassified` and `Pending` are no-ops by design (see
329	    /// `WriteClass::Unclassified` / `resolve` for the rationale).
330	    ///
331	    /// Convergence: each local can transition at most
332	    /// `Uninit → Known(n) → Generic` (two steps). Propagation chains
333	    /// `_a = _b = … = _z` are bounded by `num_locals`, so `num_locals + 2`
334	    /// iterations are guaranteed sufficient.
335	    pub fn analyze(body: &mir::Body) -> Self {
336	        let num_locals = body.locals().len();
337	        let mut classes = vec![SlotAddrSpace::Uninit; num_locals];
338	
339	        let cap = num_locals.saturating_add(2).max(2);
340	        for _ in 0..cap {
341	            let mut changed = false;
342	
343	            for block in &body.blocks {
344	                for stmt in &block.statements {
345	                    let mir::StatementKind::Assign(place, rvalue) = &stmt.kind else {
346	                        continue;
347	                    };
348	                    if !place.projection.is_empty() {
349	                        continue;
350	                    }
351	                    let class = classify_rvalue(rvalue, &classes);
352	                    if let Some(observation) = resolve(class, false)
353	                        && merge_into(&mut classes, place.local, observation)
354	                    {
355	                        changed = true;
356	                    }
357	                }
358	
359	                let mir::TerminatorKind::Call {
360	                    func, destination, ..
361	                } = &block.terminator.kind
362	                else {
363	                    continue;
364	                };
365	                if !destination.projection.is_empty() {
366	                    continue;
367	                }
368	                let class = classify_call(func);
369	                if let Some(observation) = resolve(class, false)
370	                    && merge_into(&mut classes, destination.local, observation)
371	                {
372	                    changed = true;
373	                }
374	            }
375	
376	            if !changed {
377	                break;
378	            }
379	        }
380	
381	        Self { classes }
382	    }
383	
384	    /// Effective address space for `local`'s slot pointee.
385	    ///
386	    /// - `Known(n)` → `n` (the inferred addrspace).
387	    /// - `Generic`  → `address_space::GENERIC` (writes disagreed or were
388	    ///   unclassified).
389	    /// - `Uninit`   → `rust_declared` (no classified writes seen; keep
390	    ///   whatever `translate_type` produced).
391	    pub fn effective(&self, local: mir::Local, rust_declared: u32) -> u32 {
392	        match self
393	            .classes
394	            .get(local)
395	            .copied()
396	            .unwrap_or(SlotAddrSpace::Uninit)
397	        {
398	            SlotAddrSpace::Uninit => rust_declared,
399	            SlotAddrSpace::Known(n) => n,
400	            SlotAddrSpace::Generic => address_space::GENERIC,
401	        }
402	    }
403	}
404	
405	/// Turn a [`WriteClass`] into a [`SlotAddrSpace`] observation, or `None`
406	/// when the observation should be skipped this iteration.
407	///
408	/// `Unclassified` and `Pending` both resolve to `None` ("skip"): we never
409	/// demote a slot based on lack of information. Demotion to `Generic` only
410	/// happens when two genuinely disagreeing `Classified(_)` observations hit
411	/// the same slot.
412	fn resolve(class: WriteClass, _final_pass: bool) -> Option<SlotAddrSpace> {
413	    match class {
414	        WriteClass::Classified(n) => Some(SlotAddrSpace::Known(n)),
415	        WriteClass::Unclassified | WriteClass::Pending => None,
416	    }
417	}
418	
419	/// Merge `observation` into `classes[local]`. Returns `true` if the slot's
420	/// state changed.
421	fn merge_into(
422	    classes: &mut [SlotAddrSpace],
423	    local: mir::Local,
424	    observation: SlotAddrSpace,
425	) -> bool {
426	    let Some(slot) = classes.get_mut(local) else {
427	        return false;
428	    };
429	    let merged = slot.merge(observation);
430	    if merged != *slot {
431	        *slot = merged;
432	        true
433	    } else {
434	        false
435	    }
436	}
437	
438	/// Classify the write produced by an `Assign(_, rvalue)` statement.
439	///
440	/// The rule set is intentionally narrow: when in doubt, return
441	/// [`WriteClass::Unclassified`] so the final state merges to `Generic`. The
442	/// safety invariant is "a slot is only promoted out of generic when every
443	/// write into it is confidently classified," so an incomplete classifier
444	/// at worst leaves the slot generic — i.e. today's behavior.
445	fn classify_rvalue(rvalue: &mir::Rvalue, classes: &[SlotAddrSpace]) -> WriteClass {
446	    match rvalue {
447	        // `_y = _x` — propagate `_x`'s current classification. `Move` and
448	        // `Copy` are indistinguishable for addrspace purposes. `CopyForDeref`
449	        // behaves the same at this layer.
450	        mir::Rvalue::Use(mir::Operand::Copy(place))
451	        | mir::Rvalue::Use(mir::Operand::Move(place))
452	        | mir::Rvalue::CopyForDeref(place)
453	            if place.projection.is_empty() =>
454	        {
455	            propagate_from_local(place.local, classes)
456	        }
457	        // `_y = CONSTANT` — a constant-operand pointer to a shared-memory
458	        // static (e.g. `&mut TILE_A` where `TILE_A: SharedArray<...>`)
459	        // lowers to a `mir.shared_alloc` in `translate_operand` whose
460	        // result is `addrspace(3)`. The matching `WriteClass::Classified`
461	        // here keeps the destination slot typed to match, avoiding the
462	        // otherwise-inevitable `PtrToPtr` narrow-to-generic cast.
463	        mir::Rvalue::Use(mir::Operand::Constant(const_op)) => classify_constant(const_op),
464	        // Every other rvalue shape (aggregates, arithmetic, casts, complex
465	        // projections, `Ref`/`AddressOf`, …) we decline to reason about
466	        // here. The matching `Call`-terminator classifier handles the
467	        // pointer-producing intrinsics; the remaining cases can be
468	        // tightened in a follow-up if a benchmark asks for it.
469	        _ => WriteClass::Unclassified,
470	    }
471	}
472	
473	/// Classify a constant operand's address space.
474	///
475	/// Kept in sync with `rvalue::is_shared_array_pointer` /
476	/// `is_barrier_pointer` / ordinary static handling — those gate the emitter;
477	/// this gates the slot address-space classifier.
478	fn classify_constant(const_op: &mir::ConstOperand) -> WriteClass {
479	    let ty = const_op.const_.ty();
480	    let TyKind::RigidTy(RigidTy::RawPtr(pointee, _) | RigidTy::Ref(_, pointee, _)) = ty.kind()
481	    else {
482	        return WriteClass::Unclassified;
483	    };
484	
485	    if let TyKind::RigidTy(RigidTy::Adt(adt_def, _)) = pointee.kind()
486	        && matches!(adt_def.trimmed_name().as_str(), "SharedArray" | "Barrier")
487	    {
488	        return WriteClass::Classified(address_space::SHARED);
489	    }
490	
491	    let ConstantKind::Allocated(alloc) = const_op.const_.kind() else {
492	        return WriteClass::Unclassified;
493	    };
494	    if alloc.is_null().unwrap_or(false) {
495	        return WriteClass::Unclassified;
496	    }
497	    let Some((_, prov)) = alloc.provenance.ptrs.first() else {
498	        return WriteClass::Unclassified;
499	    };
500	    match GlobalAlloc::from(prov.0) {
501	        GlobalAlloc::Static(static_def) => {
502	            // `#[constant]` statics live in addrspace(4) and are recognised
503	            // by the `ConstantMemory<T>` wrapper on the static's declared type.
504	            // Other statics live in addrspace(1).
505	            let static_ty = static_def.ty();
506	            if is_constant_wrapper_type(&static_ty) {
507	                WriteClass::Classified(address_space::CONSTANT)
508	            } else {
509	                WriteClass::Classified(address_space::GLOBAL)
510	            }
511	        }
512	        _ => WriteClass::Unclassified,
513	    }
514	}
515	
516	/// `true` if `ty` is `cuda_device::ConstantMemory<_>`. Detection by trimmed ADT
517	/// name, mirroring the `SharedArray | Barrier` check above in
518	/// [`classify_constant`].
519	pub(super) fn is_constant_wrapper_type(ty: &rustc_public::ty::Ty) -> bool {
520	    use rustc_public::ty::{RigidTy, TyKind};
521	    let TyKind::RigidTy(RigidTy::Adt(adt_def, _)) = ty.kind() else {
522	        return false;
523	    };
524	    adt_def.krate().name.as_str() == "cuda_device"
525	        && adt_def.trimmed_name().as_str() == "ConstantMemory"
526	}
527	
528	/// Classify the write produced by a `Call` terminator's destination.
529	///
530	/// Mirrors the intrinsic dispatch table in
531	/// `translator/terminator/mod.rs::try_dispatch_intrinsic`. Any intrinsic
532	/// whose emitter unconditionally produces a pointer in a specific address
533	/// space is listed here; new intrinsics should add an entry on the same
534	/// commit that adds their emitter.
535	fn classify_call(func: &mir::Operand) -> WriteClass {
536	    let mir::Operand::Constant(const_op) = func else {
537	        return WriteClass::Unclassified;
538	    };
539	    if !matches!(const_op.const_.kind(), ConstantKind::ZeroSized) {
540	        return WriteClass::Unclassified;
541	    }
542	    let TyKind::RigidTy(RigidTy::FnDef(fn_def, substs)) = const_op.const_.ty().kind() else {
543	        return WriteClass::Unclassified;
544	    };
545	    let path = fn_def.name();
546	    let substs_str = format!("{substs:?}");
547	    let on_shared_array = substs_str.contains("SharedArray");
548	
549	    // --- addrspace 3 (shared) producers -------------------------------------
550	    //
551	    // `SharedArray::index` / `IndexMut::index_mut` on a `SharedArray<T, N>`
552	    // lower to `emit_shared_array_index`, which offsets the shared-memory
553	    // base pointer and returns `*mut T addrspace(3)`.
554	    if on_shared_array
555	        && matches!(
556	            path.as_str(),
557	            "std::ops::Index::index"
558	                | "core::ops::Index::index"
559	                | "std::ops::IndexMut::index_mut"
560	                | "core::ops::IndexMut::index_mut"
561	        )
562	    {
563	        return WriteClass::Classified(address_space::SHARED);
564	    }
565	
566	    // `DynamicSharedArray::<T, ALIGN>::{get, get_raw, offset}` all hand back
567	    // pointers into the extern-shared region (`addrspace(3)`).
568	    if path.contains("DynamicSharedArray") && (path.contains("::get") || path.contains("::offset"))
569	    {
570	        return WriteClass::Classified(address_space::SHARED);
571	    }
572	
573	    // --- explicit narrow to generic -----------------------------------------
574	    //
575	    // `SharedArray::as_ptr` / `as_mut_ptr` deliberately `cvta.shared` the
576	    // base pointer into the generic address space, so the callee sees
577	    // `addrspace(0)`.
578	    if path.contains("SharedArray") && (path.contains("as_ptr") || path.contains("as_mut_ptr")) {
579	        return WriteClass::Classified(address_space::GENERIC);
580	    }
581	
582	    WriteClass::Unclassified
583	}
584	
585	/// Inherit classification from a source local (for `_y = _x` chains).
586	fn propagate_from_local(local: mir::Local, classes: &[SlotAddrSpace]) -> WriteClass {
587	    match classes.get(local).copied().unwrap_or(SlotAddrSpace::Uninit) {
588	        SlotAddrSpace::Known(n) => WriteClass::Classified(n),
589	        SlotAddrSpace::Generic => WriteClass::Unclassified,
590	        // Source hasn't been classified yet in this iteration — try again
591	        // on the next pass rather than prematurely demoting the destination.
592	        SlotAddrSpace::Uninit => WriteClass::Pending,
593	    }
594	}
595	
596	/// If `elem_ty` is a `MirPtrType`, return it with `target` replacing the
597	/// current address space; otherwise return `elem_ty` unchanged.
598	///
599	/// Used by `body::emit_entry_allocas` to override a Rust-declared pointer
600	/// addrspace with the one inferred by [`SlotAddrSpaceMap`].
601	pub fn align_pointer_addr_space(ctx: &mut Context, elem_ty: TypeHandle, target: u32) -> TypeHandle {
602	    let ptr_info = elem_ty
603	        .deref(ctx)
604	        .downcast_ref::<MirPtrType>()
605	        .map(|pt| (pt.pointee, pt.is_mutable, pt.address_space));
606	    let Some((pointee, is_mutable, current)) = ptr_info else {
607	        return elem_ty;
608	    };
609	    if current == target {
610	        return elem_ty;
611	    }
612	    MirPtrType::get(ctx, pointee, is_mutable, target).into()
613	}
614	
615	/// Extract a pointer type's address space, or `None` if `elem_ty` is not a
616	/// [`MirPtrType`]. Useful as the `rust_declared` fallback for
617	/// [`SlotAddrSpaceMap::effective`].
618	pub fn pointer_addr_space(ctx: &Context, elem_ty: TypeHandle) -> Option<u32> {
619	    elem_ty
620	        .deref(ctx)
621	        .downcast_ref::<MirPtrType>()
622	        .map(|pt| pt.address_space)
623	}
