107	            dims[i] = match c.kind() {
108	                TyConstKind::Value(_, alloc) => alloc.read_uint().ok().map(|v| v as u32),
109	                _ => c.eval_target_usize().ok().map(|v| v as u32),
110	            }
111	            .unwrap_or(dims[i]);
112	        }
113	
114	        return Some(ClusterDims {
115	            x: dims[0],
116	            y: dims[1],
117	            z: dims[2],
118	        });
119	    }
120	    None
121	}
