123	/// Scans MIR for `__launch_bounds_config::<MAX, MIN>()` marker and extracts launch bounds.
124	///
125	/// The `#[launch_bounds(max, min)]` macro injects this call at the start of the kernel.
126	/// We scan the MIR to find it and extract the const generic parameters.
127	///
128	/// Returns `Some(LaunchBounds)` if found, `None` otherwise.
129	fn detect_launch_bounds_config(body: &mir::Body) -> Option<LaunchBounds> {
130	    use rustc_public::ty::TyConstKind;
131	
132	    for block in &body.blocks {
133	        let mir::TerminatorKind::Call { func, .. } = &block.terminator.kind else {
134	            continue;
135	        };
136	        let mir::Operand::Constant(constant) = func else {
137	            continue;
138	        };
139	        let ConstantKind::ZeroSized = constant.const_.kind() else {
140	            continue;
141	        };
142	        let TyKind::RigidTy(RigidTy::FnDef(def_id, args)) = constant.const_.ty().kind() else {
143	            continue;
144	        };
145	
146	        let fn_name = def_id.name();
147	        if fn_name != "__launch_bounds_config" && !fn_name.ends_with("::__launch_bounds_config") {
148	            continue;
149	        }
150	
151	        // Extract const generic args (MAX_THREADS, MIN_BLOCKS)
152	        let mut values = [0u32, 0u32];
153	        for (i, arg) in args.0.iter().take(2).enumerate() {
154	            let rustc_public::ty::GenericArgKind::Const(c) = arg else {
155	                continue;
156	            };
157	            values[i] = match c.kind() {
158	                TyConstKind::Value(_, alloc) => alloc.read_uint().ok().map(|v| v as u32),
159	                _ => c.eval_target_usize().ok().map(|v| v as u32),
160	            }
161	            .unwrap_or(values[i]);
162	        }
163	
164	        return Some(LaunchBounds {
165	            max_threads: values[0],
166	            min_blocks: values[1],
167	        });
168	    }
169	    None
170	}
