172	/// Return the non-unwind successors of a terminator.
173	///
174	/// [`mir::Terminator::successors`] includes unwind cleanup blocks alongside
175	/// "normal" control-flow targets. The CUDA toolchain does not support stack
176	/// unwinding (hardware could, but `nvcc`/`ptxas` never wire it up), so the
177	/// translator treats unwind cleanups as dead code. This helper strips them
178	/// out so the worklist only visits blocks that matter on GPU.
179	fn non_unwind_successors(kind: &mir::TerminatorKind) -> Vec<usize> {
180	    use mir::TerminatorKind::*;
181	    match kind {
182	        Goto { target } => vec![*target],
183	        SwitchInt { targets, .. } => targets.all_targets(),
184	        Return | Resume | Abort | Unreachable => vec![],
185	        Drop { target, .. } | Assert { target, .. } => vec![*target],
186	        Call { target, .. } => target.map(|t| vec![t]).unwrap_or_default(),
187	        InlineAsm { destination, .. } => destination.map(|t| vec![t]).unwrap_or_default(),
188	    }
189	}
190	
191	/// BFS from the entry block (index 0) following non-unwind successors.
192	///
193	/// The result is a sorted set of reachable-on-GPU block indices; unwind-only
194	/// cleanup blocks end up outside this set and are filled in with
195	/// `mir.unreachable` by [`translate_body`] so pliron verification still
196	/// passes.
197	fn compute_reachable_blocks(body: &mir::Body) -> std::collections::BTreeSet<usize> {
198	    let mut reachable = std::collections::BTreeSet::new();
199	    let mut frontier: Vec<usize> = vec![0];
200	    reachable.insert(0);
201	    while let Some(idx) = frontier.pop() {
202	        let successors = non_unwind_successors(&body.blocks[idx].terminator.kind);
203	        for succ in successors {
204	            if reachable.insert(succ) {
205	                frontier.push(succ);
206	            }
207	        }
208	    }
209	    reachable
210	}
