219	/// Build the first full-debug variable map.
220	///
221	/// This stage only supports simple whole-local bindings:
222	///
223	/// ```text
224	/// debug name => _3
225	/// ```
226	///
227	/// Fragments/projections need `DIExpression(DW_OP_LLVM_fragment, ...)` and more
228	/// value-location tracking, so they are intentionally skipped until the basic
229	/// local/argument path is solid.
230	fn collect_debug_locals(
231	    ctx: &mut Context,
232	    body: &mir::Body,
233	) -> FxHashMap<mir::Local, LocalDebugInfo> {
234	    let mut locals = FxHashMap::default();
235	
236	    for info in &body.var_debug_info {
237	        if info.composite.is_some() {
238	            continue;
239	        }
240	
241	        let Some(local) = info.local() else {
242	            continue;
243	        };
244	        let local_idx: usize = local;
245	        if local_idx == 0 {
246	            continue;
247	        }
248	
249	        let Some(decl) = body.local_decl(local) else {
250	            continue;
251	        };
252	        let Some(ty) = debug_type_for_ty(&decl.ty) else {
253	            continue;
254	        };
255	
256	        let name = info.name.to_string();
257	        if name.is_empty() {
258	            continue;
259	        }
260	
261	        locals.entry(local).or_insert_with(|| LocalDebugInfo {
262	            variable: DebugLocalVariableInfo {
263	                name,
264	                argument_index: info.argument_index,
265	                ty,
266	            },
267	            loc: span_to_location(ctx, info.source_info.span),
268	            source_scope: info.source_info.scope,
269	        });
270	    }
271	
272	    locals
273	}
