275	/// Maximum nesting depth for composite debug types. Guards against deeply
276	/// nested or (via generics) pathological value-type trees; beyond this we omit
277	/// the inner detail rather than recurse without bound.
278	const MAX_DEBUG_TYPE_DEPTH: usize = 8;
279	
280	fn debug_type_for_ty(ty: &Ty) -> Option<DebugLocalTypeKind> {
281	    debug_type_for_ty_at(ty, 0)
282	}
283	
284	fn debug_type_for_ty_at(ty: &Ty, depth: usize) -> Option<DebugLocalTypeKind> {
285	    match ty.kind() {
286	        TyKind::RigidTy(RigidTy::Bool) => Some(DebugLocalTypeKind::Basic {
287	            name: "bool".to_string(),
288	            size_bits: 8,
289	            encoding: "DW_ATE_boolean",
290	        }),
291	        TyKind::RigidTy(RigidTy::Int(int_ty)) => Some(DebugLocalTypeKind::Basic {
292	            name: int_name(int_ty).to_string(),
293	            size_bits: (int_ty.num_bytes() * 8) as u64,
294	            encoding: "DW_ATE_signed",
295	        }),
296	        TyKind::RigidTy(RigidTy::Uint(uint_ty)) => Some(DebugLocalTypeKind::Basic {
297	            name: uint_name(uint_ty).to_string(),
298	            size_bits: (uint_ty.num_bytes() * 8) as u64,
299	            encoding: "DW_ATE_unsigned",
300	        }),
301	        TyKind::RigidTy(RigidTy::Float(float_ty)) => Some(DebugLocalTypeKind::Basic {
302	            name: float_name(float_ty).to_string(),
303	            size_bits: float_size_bits(float_ty),
304	            encoding: "DW_ATE_float",
305	        }),
306	        TyKind::RigidTy(RigidTy::RawPtr(pointee, mutability)) => {
307	            Some(DebugLocalTypeKind::Pointer {
308	                name: raw_pointer_name(pointee, mutability),
309	                size_bits: 64,
310	            })
311	        }
312	        TyKind::RigidTy(RigidTy::Ref(_, pointee, mutability)) => {
313	            Some(DebugLocalTypeKind::Pointer {
314	                name: reference_name(pointee, mutability),
315	                size_bits: 64,
316	            })
317	        }
318	        TyKind::RigidTy(RigidTy::Tuple(subtypes)) if depth < MAX_DEBUG_TYPE_DEPTH => {
319	            let name = format!(
320	                "({})",
321	                subtypes
322	                    .iter()
323	                    .map(short_ty_name)
324	                    .collect::<Vec<_>>()
325	                    .join(", ")
326	            );
327	            let fields = subtypes
328	                .iter()
329	                .enumerate()
330	                .map(|(idx, sub)| (format!("__{idx}"), *sub));
331	            debug_struct_type(ty, name, fields, depth)
332	        }
333	        TyKind::RigidTy(RigidTy::Adt(adt_def, substs)) if depth < MAX_DEBUG_TYPE_DEPTH => {
334	            // Only plain structs (one variant) are described as composites here;
335	            // enums and unions need DWARF variant parts (deferred).
336	            if !matches!(adt_def.kind(), rustc_public::ty::AdtKind::Struct) {
337	                return None;
338	            }
339	            let variants = adt_def.variants();
340	            if variants.len() != 1 {
341	                return None;
342	            }
343	            let name = adt_def.trimmed_name();
344	            let fields = variants[0]
345	                .fields()
346	                .into_iter()
347	                .map(|field| (field.name.to_string(), field.ty_with_args(&substs)));
348	            debug_struct_type(ty, name, fields, depth)
349	        }
350	        TyKind::RigidTy(RigidTy::Array(elem_ty, len_const)) if depth < MAX_DEBUG_TYPE_DEPTH => {
351	            let count = array_len_const(&len_const)?;
352	            let element = debug_type_for_ty_at(&elem_ty, depth + 1)?;
353	            let size_bits = layout_size_bits(ty)?;
354	            Some(DebugLocalTypeKind::Array {
355	                name: format!("[{}; {count}]", short_ty_name(&elem_ty)),
356	                size_bits,
357	                element: Box::new(element),
358	                count,
359	            })
360	        }
361	        _ => None,
362	    }
363	}
