365	/// Build a `DICompositeType`-shaped struct/tuple from rustc's real layout.
366	///
367	/// Member offsets come from `ty.layout()` (so `repr(Rust)` field reordering is
368	/// honored), not declaration order. Fields whose type we cannot yet describe,
369	/// and zero-sized fields (e.g. `PhantomData`), are omitted; the remaining
370	/// members keep their correct offsets.
371	fn debug_struct_type(
372	    ty: &Ty,
373	    name: String,
374	    fields: impl Iterator<Item = (String, Ty)>,
375	    depth: usize,
376	) -> Option<DebugLocalTypeKind> {
377	    let layout = ty.layout().ok()?;
378	    let shape = layout.shape();
379	    let offsets: Vec<u64> = match &shape.fields {
380	        rustc_public::abi::FieldsShape::Arbitrary { offsets } => {
381	            offsets.iter().map(|off| off.bytes() as u64).collect()
382	        }
383	        _ => return None,
384	    };
385	    let size_bits = shape.size.bytes() as u64 * 8;
386	
387	    let mut members = Vec::new();
388	    for (idx, (field_name, field_ty)) in fields.enumerate() {
389	        let offset_bytes = *offsets.get(idx)?;
390	        let Some(member_ty) = debug_type_for_ty_at(&field_ty, depth + 1) else {
391	            continue;
392	        };
393	        if member_ty.size_bits() == 0 {
394	            continue;
395	        }
396	        members.push(DebugTypeMember {
397	            name: field_name,
398	            offset_bits: offset_bytes * 8,
399	            ty: member_ty,
400	        });
401	    }
402	
403	    if members.is_empty() {
404	        return None;
405	    }
406	
407	    Some(DebugLocalTypeKind::Struct {
408	        name,
409	        size_bits,
410	        members,
411	    })
412	}
413	
414	/// Total size of `ty` in bits from its layout, or `None` if unavailable.
415	fn layout_size_bits(ty: &Ty) -> Option<u64> {
416	    Some(ty.layout().ok()?.shape().size.bytes() as u64 * 8)
417	}
