419	/// Evaluate a fixed array's length constant to a `u64`.
420	fn array_len_const(len_const: &rustc_public::ty::TyConst) -> Option<u64> {
421	    match len_const.kind() {
422	        rustc_public::ty::TyConstKind::Value(_, alloc) => {
423	            let mut arr = [0u8; 8];
424	            for (i, byte) in alloc.bytes.iter().take(8).enumerate() {
425	                arr[i] = (*byte)?;
426	            }
427	            Some(u64::from_le_bytes(arr))
428	        }
429	        _ => None,
430	    }
431	}
