514	/// Emit one `mir.alloca` per non-ZST MIR local at the top of the entry block,
515	/// then store each function argument into its backing slot.
516	///
517	/// This is the foundation of the alloca + load/store translator model: every
518	/// non-ZST MIR local is backed by a single stack slot recorded in `value_map`
519	/// via [`ValueMap::set_slot`]. Function arguments (which arrive as entry-block
520	/// arguments) are immediately stored into their slots so subsequent blocks can
521	/// load them without needing SSA block arguments.
522	///
523	/// `num_args` is the number of function arguments (MIR locals `1..=num_args`).
524	///
525	/// Returns the last operation emitted, so the caller can pass it to
526	/// [`block::translate_block`] as `entry_prev_op` to append block contents
527	/// **after** this setup (otherwise `insert_at_front` would push the alloca
528	/// chain past the block terminator).
529	///
530	/// # ZST locals
531	///
532	/// Locals whose Rust type is zero-sized (unit tuple, empty structs, `!`, …)
533	/// are skipped entirely: they get no slot in [`ValueMap`] and any attempted
534	/// load/store short-circuits.
535	///
536	/// # Unsupported types
537	///
538	/// [`types::translate_type`] can fail for locals whose types aren't supported
539	/// yet (e.g. ghost locals in kernels targeting unsupported surfaces). Those
540	/// locals simply get no slot; any later attempt to use them still errors out
541	/// through the existing unsupported-type code paths.
542	fn emit_entry_allocas(
543	    ctx: &mut Context,
544	    body: &mir::Body,
545	    entry_block: Ptr<BasicBlock>,
546	    num_args: usize,
547	    value_map: &mut ValueMap,
548	    debug_kind: DebugKind,
549	    debug_source_scopes: Option<&DebugSourceScopeMap>,
550	) -> Option<Ptr<Operation>> {
551	    let mut prev_op: Option<Ptr<Operation>> = None;
552	    let debug_locals = if debug_kind.variables_enabled() {
553	        collect_debug_locals(ctx, body)
554	    } else {
555	        FxHashMap::default()
556	    };
557	
558	    // Pre-scan the body once: for each local whose translated slot type is a
559	    // pointer, infer the address space from the *writes* into it rather than
560	    // trusting Rust's declared type (which loses addrspace info for
561	    // references / raw pointers).
562	    let slot_addr_spaces = SlotAddrSpaceMap::analyze(body);
563	
564	    for local_idx in 0..body.locals().len() {
565	        let local = mir::Local::from(local_idx);
566	        let local_ty = &body.locals()[local].ty;
567	        if types::is_rust_type_zst(local_ty) {
568	            continue;
569	        }
570	        let mir_ty = match types::translate_type(ctx, local_ty) {
571	            Ok(t) => t,
572	            Err(_) => continue,
573	        };
574	
575	        // Override the Rust-declared addrspace with the inferred one for
576	        // pointer slots. Non-pointer slots are untouched by
577	        // `align_pointer_addr_space`.
578	        let rust_declared =
579	            values::pointer_addr_space(ctx, mir_ty).unwrap_or(address_space::GENERIC);
580	        let target = slot_addr_spaces.effective(local, rust_declared);
581	        let mir_ty = values::align_pointer_addr_space(ctx, mir_ty, target);
582	
583	        let (op, slot) = ValueMap::emit_alloca(ctx, mir_ty, entry_block, prev_op);
584	        if let Some(info) = debug_locals.get(&local) {
585	            llvm_export::ops::set_debug_local_variable(ctx, op, info.variable.clone());
586	            if debug_source_scopes
587	                .is_some_and(|map| map.scopes.iter().any(|scope| scope.id == info.source_scope))
588	            {
589	                llvm_export::ops::set_debug_local_source_scope(ctx, op, info.source_scope);
590	            }
591	            op.deref_mut(ctx).set_loc(info.loc.clone());
592	        }
593	        prev_op = Some(op);
594	        value_map.set_slot(local, slot);
595	    }
596	
597	    for arg_idx in 0..num_args {
598	        let local = mir::Local::from(arg_idx + 1);
599	        let block_arg = entry_block.deref(ctx).get_argument(arg_idx);
600	        if let Some(op) = value_map.store_local(ctx, local, block_arg, entry_block, prev_op) {
601	            prev_op = Some(op);
602	        }
603	    }
604	
605	    prev_op
606	}
