608	/// Translates a MIR function body to a pliron IR `mir.func` operation.
609	///
610	/// # Process
611	///
612	/// 1. Extract signature (arg types from MIR locals 1..N, return from local 0)
613	/// 2. Create `mir.func` with signature and optional `gpu_kernel` attribute
614	/// 3. Create one pliron block per MIR block. The entry block carries the
615	///    function parameters; every other block is argument-less (cross-block
616	///    data flow travels through per-local alloca slots)
617	/// 4. Emit one `mir.alloca` per non-ZST local at the top of the entry block
618	///    and seed the argument slots from the block's parameters
619	/// 5. Translate every reachable block in index order
620	///
621	/// # Arguments
622	///
623	/// * `ctx` - Pliron IR context
624	/// * `body` - MIR function body
625	/// * `instance` - Monomorphized instance (with concrete generic args)
626	/// * `is_kernel` - Add `gpu_kernel` attribute for kernel entry points
627	/// * `is_inline_always` - Add `alwaysinline` attribute (non-kernel functions
628	///   marked `#[inline(always)]` in rustc)
629	/// * `override_name` - Custom export name (defaults to instance name)
630	pub fn translate_body(
631	    ctx: &mut Context,
632	    body: &mir::Body,
633	    instance: &mono::Instance,
634	    is_kernel: bool,
635	    is_inline_always: bool,
636	    override_name: Option<&str>,
637	    legaliser: &mut Legaliser,
638	    debug_kind: DebugKind,
639	    debug_source_scopes: Option<&DebugSourceScopeMap>,
640	) -> TranslationResult<Ptr<Operation>> {
641	    // Create a value map to track MIR locals -> pliron IR values
642	    let num_locals = body.locals().len();
643	    let mut value_map = ValueMap::new(num_locals);
644	
645	    // Get function argument types for the first block
646	    // In MIR, locals[0] is the return value, locals[1..arg_count+1] are function arguments
647	    let mut arg_types = Vec::new();
648	
649	    // Determine argument count from the function type in the instance
650	    // Get the function signature to determine the number of arguments
651	    let fn_ty = instance.ty();
652	    let num_args = match fn_ty.kind() {
653	        rustc_public::ty::TyKind::RigidTy(rustc_public::ty::RigidTy::FnDef(_, _)) => {
654	            // Get the function signature from fn_sig()
655	            let sig_binder = fn_ty.kind().fn_sig().unwrap();
656	            // Skip the binder to get the actual signature
657	            let sig = sig_binder.skip_binder();
658	            let inputs = sig.inputs();
659	            inputs.len()
660	        }
661	        rustc_public::ty::TyKind::RigidTy(rustc_public::ty::RigidTy::Closure(_, _)) => {
662	            // Closures use RustCall ABI where:
663	            // - MIR local 1 = self (closure environment, even if ZST)
664	            // - MIR locals 2..N = unpacked arguments from the fn_sig's tuple input
665	            //
666	            // fn_sig().inputs() returns just the tuple, NOT including self.
667	            // We need to count: 1 (self) + unpacked tuple elements
668	            let sig_binder = fn_ty.kind().fn_sig().unwrap();
669	            let sig = sig_binder.skip_binder();
670	            let inputs = sig.inputs();
671	
672	            // The input should be a single tuple (RustCall convention)
673	            let tuple_arg_count = if inputs.len() == 1 {
674	                // Get the tuple type and count its elements
675	                if let rustc_public::ty::TyKind::RigidTy(rustc_public::ty::RigidTy::Tuple(
676	                    tuple_tys,
677	                )) = inputs[0].kind()
678	                {
679	                    tuple_tys.len()
680	                } else {
681	                    // Not a tuple - use 1 (single arg)
682	                    1
683	                }
684	            } else {
685	                // Multiple inputs (shouldn't happen with RustCall, but handle it)
686	                inputs.len()
687	            };
688	
689	            // Total args = 1 (self) + unpacked tuple elements
690	            1 + tuple_arg_count
691	        }
692	        _ => {
693	            return input_err_noloc!(TranslationErr::unsupported(format!(
694	                "Expected FnDef or Closure type for function, got {:?}",
695	                fn_ty.kind()
696	            )));
697	        }
698	    };
699	
700	    for arg_idx in 0..num_args {
701	        // MIR local index for arguments: local 1, 2, 3, ... (0 is return value)
702	        let local = mir::Local::from(arg_idx + 1);
703	        let local_decl = &body.locals()[local];
704	        let ty = &local_decl.ty;
705	        let arg_type = types::translate_type(ctx, ty)?;
706	        arg_types.push(arg_type);
707	    }
708	
709	    // Get return type (local 0)
710	    let return_local = mir::Local::from(0usize);
711	    let return_decl = &body.locals()[return_local];
712	    let return_type_ptr = types::translate_type(ctx, &return_decl.ty)?;
713	
714	    // Unit-tuple returns become a void `mir.func` signature. We skip the
715	    // result so `MirReturnOp` isn't expected to carry an unused `()` operand
716	    // (`mir-lower` reconstructs the unit value at LLVM lowering time).
717	    let is_unit_return = {
718	        let return_type_obj = return_type_ptr.deref(ctx);
719	        if let Some(tuple_ty) = return_type_obj.downcast_ref::<dialect_mir::types::MirTupleType>() {
720	            tuple_ty.get_types().is_empty()
721	        } else {
722	            false
723	        }
724	    };
725	
726	    let return_types = if is_unit_return {
727	        vec![]
728	    } else {
729	        vec![return_type_ptr]
730	    };
731	
732	    // Create function type for signature
733	    use pliron::builtin::attributes::TypeAttr;
734	    use pliron::builtin::types::FunctionType;
735	    let func_type = FunctionType::get(
736	        ctx,
737	        arg_types.clone(), // inputs
738	        return_types,      // results
739	    );
740	    let func_type_attr = TypeAttr::new(func_type.into());
741	
742	    // Create a mir.func operation with a region for the function body
743	    let op_ptr = Operation::new(
744	        ctx,
745	        MirFuncOp::get_concrete_op_info(),
746	        vec![], // No result types
747	        vec![], // No operands
748	        vec![], // No successors
749	        1,      // 1 region for function body
750	    );
751	
752	    // Set the function location from rustc's body span. This becomes the
753	    // default scope line for line-table debug info once LLVM export is enabled.
754	    let loc = span_to_location(ctx, body.span);
755	    op_ptr.deref_mut(ctx).set_loc(loc);
756	
757	    // Create MirFuncOp and set the function type attribute and symbol name
758	    let mir_func_op = MirFuncOp::new(ctx, op_ptr, func_type_attr);
759	
760	    let name_str = if let Some(name) = override_name {
761	        name.to_string()
762	    } else {
763	        instance.name().to_string()
764	    };
765	    mir_func_op.set_symbol_name(ctx, legaliser.legalise(&name_str));
766	
767	    // Check if the function has the #[cuda_oxide::kernel] attribute (passed via is_kernel flag)
768	    if is_kernel {
769	        // Add "gpu_kernel" attribute to the mir.func operation.
770	        // This will be used by the lowering pass to set the "gpu_kernel" attribute on the llvm.func.
771	        use pliron::builtin::attributes::StringAttr;
772	        let kernel_attr = StringAttr::new("true".to_string());
773	        let key: Identifier = "gpu_kernel".try_into().unwrap();
774	        mir_func_op
775	            .get_operation()
776	            .deref_mut(ctx)
777	            .attributes
778	            .set(key, kernel_attr);
779	
780	        // Detect compile-time cluster configuration from #[cluster(x,y,z)] attribute
781	        if let Some(cluster_dims) = detect_cluster_config(body) {
782	            use pliron::builtin::attributes::IntegerAttr;
783	            use pliron::builtin::types::Signedness;
784	            use pliron::utils::apint::APInt;
785	            use std::num::NonZero;
786	
787	            // Add cluster_dim_x/y/z attributes
788	            // These will be used by the LLVM export to emit nvvm.annotations metadata
789	            let u32_ty = pliron::builtin::types::IntegerType::get(ctx, 32, Signedness::Unsigned);
790	            let width = NonZero::new(32).unwrap();
791	
792	            // Create APInt values for each dimension
793	            let apint_x = APInt::from_u32(cluster_dims.x, width);
794	            let apint_y = APInt::from_u32(cluster_dims.y, width);
795	            let apint_z = APInt::from_u32(cluster_dims.z, width);
796	
797	            let x_attr = IntegerAttr::new(u32_ty, apint_x);
798	            let y_attr = IntegerAttr::new(u32_ty, apint_y);
799	            let z_attr = IntegerAttr::new(u32_ty, apint_z);
800	
801	            let x_key: Identifier = "cluster_dim_x".try_into().unwrap();
802	            let y_key: Identifier = "cluster_dim_y".try_into().unwrap();
803	            let z_key: Identifier = "cluster_dim_z".try_into().unwrap();
804	
805	            let mut op_mut = mir_func_op.get_operation().deref_mut(ctx);
806	            op_mut.attributes.set(x_key, x_attr);
807	            op_mut.attributes.set(y_key, y_attr);
808	            op_mut.attributes.set(z_key, z_attr);
809	
810	            if std::env::var("CUDA_OXIDE_VERBOSE").is_ok() {
811	                eprintln!(
812	                    "  Cluster config detected: {}x{}x{}",
813	                    cluster_dims.x, cluster_dims.y, cluster_dims.z
814	                );
815	            }
816	        }
817	
818	        // Detect compile-time launch bounds from #[launch_bounds(max, min)] attribute
819	        if let Some(launch_bounds) = detect_launch_bounds_config(body) {
820	            use pliron::builtin::attributes::IntegerAttr;
821	            use pliron::builtin::types::Signedness;
822	            use pliron::utils::apint::APInt;
823	            use std::num::NonZero;
824	
825	            // Add maxntid and minctasm attributes
826	            // These will be used by the LLVM export to emit nvvm.annotations metadata
827	            let u32_ty = pliron::builtin::types::IntegerType::get(ctx, 32, Signedness::Unsigned);
828	            let width = NonZero::new(32).unwrap();
829	
830	            // Create APInt values
831	            let apint_max = APInt::from_u32(launch_bounds.max_threads, width);
832	            let max_attr = IntegerAttr::new(u32_ty, apint_max);
833	            let max_key: Identifier = "maxntid".try_into().unwrap();
834	
835	            let mut op_mut = mir_func_op.get_operation().deref_mut(ctx);
836	            op_mut.attributes.set(max_key, max_attr);
837	
838	            // Only add minctasm if it's non-zero (specified)
839	            if launch_bounds.min_blocks > 0 {
840	                let apint_min = APInt::from_u32(launch_bounds.min_blocks, width);
841	                let min_attr = IntegerAttr::new(u32_ty, apint_min);
842	                let min_key: Identifier = "minctasm".try_into().unwrap();
843	                op_mut.attributes.set(min_key, min_attr);
844	            }
845	
846	            if std::env::var("CUDA_OXIDE_VERBOSE").is_ok() {
847	                if launch_bounds.min_blocks > 0 {
848	                    eprintln!(
849	                        "  Launch bounds detected: maxntid={}, minctasm={}",
850	                        launch_bounds.max_threads, launch_bounds.min_blocks
851	                    );
852	                } else {
853	                    eprintln!(
854	                        "  Launch bounds detected: maxntid={}",
855	                        launch_bounds.max_threads
856	                    );
857	                }
858	            }
859	        }
860	    }
861	
862	    if let Some(scope_map) = debug_source_scopes
863	        && debug_kind.variables_enabled()
864	    {
865	        llvm_export::ops::set_debug_source_scope_map(ctx, op_ptr, scope_map);
866	    }
867	
868	    set_alwaysinline_attr_from_flag(ctx, &mir_func_op, is_kernel, is_inline_always);
869	
870	    // Get the function body region (region 0)
871	    let region_ptr = op_ptr.deref(ctx).get_region(0);
872	
873	    // -------------------------------------------------------------------------
874	    // PHASE 1: Create all pliron IR blocks
875	    // -------------------------------------------------------------------------
876	    //
877	    // Only the entry block receives block arguments (the function's formal
878	    // parameters). Every other block is argument-less: cross-block data flow
879	    // travels through the per-local alloca slots, not block arguments.
880	    let mut block_map: Vec<Ptr<BasicBlock>> = Vec::new();
881	
882	    for (idx, _mir_block) in body.blocks.iter().enumerate() {
883	        let arg_types_for_block = if idx == 0 { arg_types.clone() } else { vec![] };
884	
885	        let block_ptr = BasicBlock::new(ctx, None, arg_types_for_block);
886	        block_map.push(block_ptr);
887	    }
888	
889	    // Link all blocks into the function's region.
890	    for (idx, block_ptr) in block_map.iter().enumerate() {
891	        if idx == 0 {
892	            block_ptr.insert_at_front(region_ptr, ctx);
893	        } else {
894	            block_ptr.insert_after(ctx, block_map[idx - 1]);
895	        }
896	    }
897	
898	    // -------------------------------------------------------------------------
899	    // PHASE 1.5: Entry-block allocas + argument stores
900	    // -------------------------------------------------------------------------
901	    //
902	    // Every non-ZST MIR local is backed by a single stack slot emitted at the
903	    // top of the entry block; its pointer is recorded in `value_map` via
904	    // `set_slot`. Function arguments are eagerly stored into their slots so
905	    // later blocks can `load_local` them without needing block arguments.
906	    //
907	    // The `mem2reg` pass in `pipeline.rs` promotes the scalar slots back into
908	    // SSA before LLVM lowering.
909	    let entry_last_op = emit_entry_allocas(
910	        ctx,
911	        body,
912	        block_map[0],
913	        num_args,
914	        &mut value_map,
915	        debug_kind,
916	        debug_source_scopes,
917	    );
918	
919	    // -------------------------------------------------------------------------
920	    // PHASE 2: Translate reachable blocks
921	    // -------------------------------------------------------------------------
922	    //
923	    // Every local flows through its stack slot, so blocks have no inter-block
924	    // ordering dependency and can be translated in a single index-order pass.
925	    // Unwind-only cleanup blocks are skipped here (see
926	    // [`non_unwind_successors`]) and patched with `mir.unreachable` below.
927	    let reachable: std::collections::BTreeSet<usize> = compute_reachable_blocks(body);
928	
929	    let mut blocks_processed: std::collections::HashSet<usize> = std::collections::HashSet::new();
930	
931	    for idx in reachable.iter().copied() {
932	        let mir_block = &body.blocks[idx];
933	        let block_ptr = block_map[idx];
934	        let entry_prev_op = if idx == 0 { entry_last_op } else { None };
935	        block::translate_block(
936	            ctx,
937	            body,
938	            mir_block,
939	            idx,
940	            block_ptr,
941	            &mut value_map,
942	            &block_map,
943	            legaliser,
944	            entry_prev_op,
945	        )?;
946	        blocks_processed.insert(idx);
947	    }
948	
949	    // Unwind cleanup blocks are unreachable on GPU but pliron still requires
950	    // every block to have a terminator, so we stitch `mir.unreachable` onto
951	    // the ones we skipped above. Later passes are free to drop them as dead
952	    // code.
953	    for (idx, &block_ptr) in block_map.iter().enumerate().take(body.blocks.len()) {
954	        if !blocks_processed.contains(&idx) {
955	            let unreachable_op = Operation::new(
956	                ctx,
957	                dialect_mir::ops::MirUnreachableOp::get_concrete_op_info(),
958	                vec![],
959	                vec![],
960	                vec![],
961	                0,
962	            );
963	            unreachable_op.insert_at_front(block_ptr, ctx);
964	        }
965	    }
966	
967	    Ok(op_ptr)
968	}
969	
970	/// Propagate `#[inline(always)]` as an LLVM `alwaysinline` function
971	/// attribute. Kernel entry points are excluded because they're `.entry` in PTX
972	/// and never callees, so marking them `alwaysinline` would be a no-op at best
973	/// and rejected by LLVM at worst.
974	fn set_alwaysinline_attr_from_flag(
975	    ctx: &mut Context,
976	    mir_func_op: &MirFuncOp,
977	    is_kernel: bool,
978	    is_inline_always: bool,
979	) {
980	    if is_inline_always && !is_kernel {
981	        let attr = pliron::builtin::attributes::StringAttr::new("true".to_string());
982	        let key: Identifier = "alwaysinline".try_into().unwrap();
983	        mir_func_op
984	            .get_operation()
985	            .deref_mut(ctx)
986	            .attributes
987	            .set(key, attr);
988	    }
989	}
990	
991	#[cfg(test)]
992	mod tests {
993	    use super::*;
994	    use pliron::{
995	        basic_block::BasicBlock,
996	        builtin::{
997	            attributes::TypeAttr, op_interfaces::SymbolOpInterface, ops::ModuleOp,
998	            types::FunctionType,
999	        },
1000	        linked_list::ContainsLinkedList,
1001	        op::Op,
1002	        operation::Operation,
1003	    };
1004	
1005	    #[test]
1006	    fn inline_always_flag_reaches_llvm_func_attr_before_export() {
1007	        let mut ctx = Context::new();
1008	        crate::translator::register_dialects(&mut ctx);
1009	
1010	        let module = ModuleOp::new(&mut ctx, "test_module".try_into().unwrap());
1011	        let module_op = module.get_operation();
1012	        let module_region = module_op.deref(&ctx).get_region(0);
1013	        let module_block = {
1014	            let existing = {
1015	                let region = module_region.deref(&ctx);
1016	                region.iter(&ctx).next()
1017	            };
1018	            if let Some(block) = existing {
1019	                block
1020	            } else {
1021	                let block = BasicBlock::new(&mut ctx, None, vec![]);
1022	                block.insert_at_back(module_region, &ctx);
1023	                block
1024	            }
1025	        };
1026	
1027	        let func_type = FunctionType::get(&ctx, vec![], vec![]);
1028	        let func_type_attr = TypeAttr::new(func_type.into());
1029	        let mir_func = {
1030	            let op = Operation::new(
1031	                &mut ctx,
1032	                MirFuncOp::get_concrete_op_info(),
1033	                vec![],
1034	                vec![],
1035	                vec![],
1036	                1,
1037	            );
1038	            let func = MirFuncOp::new(&mut ctx, op, func_type_attr);
1039	            func.set_symbol_name(&mut ctx, "inline_helper".try_into().unwrap());
1040	            func
1041	        };
1042	
1043	        set_alwaysinline_attr_from_flag(&mut ctx, &mir_func, false, true);
1044	        mir_func.get_operation().insert_at_back(module_block, &ctx);
1045	
1046	        mir_lower::register(&mut ctx);
1047	        mir_lower::lower_mir_to_llvm(&mut ctx, module_op).expect("lowering succeeds");
1048	
1049	        let llvm_func = {
1050	            let block = module_region.deref(&ctx).iter(&ctx).next().unwrap();
1051	            block
1052	                .deref(&ctx)
1053	                .iter(&ctx)
1054	                .find_map(|op| Operation::get_op::<llvm_export::ops::FuncOp>(op, &ctx))
1055	                .expect("lowered LLVM function")
1056	        };
1057	
1058	        let key: Identifier = "alwaysinline".try_into().unwrap();
1059	        assert!(
1060	            llvm_func
1061	                .get_operation()
1062	                .deref(&ctx)
1063	                .attributes
1064	                .0
1065	                .contains_key(&key),
1066	            "`is_inline_always` must become an LLVM dialect alwaysinline attribute before export",
1067	        );
1068	    }
1069	}
