21	// No #![cfg_attr(cuda_device, no_std)] - this compiles as ONE unit!
22	
23	use cuda_core::{CudaContext, DeviceBuffer, LaunchConfig};
24	use cuda_device::{DisjointSlice, cuda_module, kernel, thread};
25	
26	// =============================================================================
27	// KERNEL - This gets compiled to PTX by rustc-codegen-cuda
28	// =============================================================================
29	
30	/// Vector addition kernel: c[i] = a[i] + b[i]
31	///
32	/// This function exists in BOTH host MIR and device PTX:
33	/// - Host: The function body is never called, but types are checked
34	/// - Device: Compiled to PTX via mir-importer pipeline
35	#[cuda_module]
36	mod kernels {
37	    use super::*;
38	
39	    #[kernel]
40	    pub fn vecadd(a: &[f32], b: &[f32], mut c: DisjointSlice<f32>) {
41	        let idx = thread::index_1d();
42	        let idx_raw = idx.get();
43	        if let Some(c_elem) = c.get_mut(idx) {
44	            *c_elem = a[idx_raw] + b[idx_raw];
45	        }
46	    }
47	}
48	
49	// =============================================================================
50	// HOST CODE - This gets compiled to native x86_64 by LLVM
51	// =============================================================================
52	
53	fn main() {
54	    println!("=== Unified Compilation Vector Addition ===\n");
55	
56	    // Initialize CUDA
57	    let ctx = CudaContext::new(0).expect("Failed to create CUDA context");
58	    let stream = ctx.default_stream();
59	
60	    // Test data
61	    const N: usize = 1024;
62	    let a_host: Vec<f32> = (0..N).map(|i| i as f32).collect();
63	    let b_host: Vec<f32> = (0..N).map(|i| (i * 2) as f32).collect();
64	
65	    println!("Input vectors (first 5 elements):");
66	    println!("  a = {:?}", &a_host[0..5]);
67	    println!("  b = {:?}", &b_host[0..5]);
68	
69	    // Allocate device memory
70	    let a_dev = DeviceBuffer::from_host(&stream, &a_host).unwrap();
71	    let b_dev = DeviceBuffer::from_host(&stream, &b_host).unwrap();
72	    let mut c_dev = DeviceBuffer::<f32>::zeroed(&stream, N).unwrap();
73	
74	    // Load the embedded PTX bundle and launch through the typed module API.
75	    let module = kernels::load(&ctx).expect("Failed to load embedded CUDA module");
76	    module
77	        .vecadd(
78	            &stream,
79	            LaunchConfig::for_num_elems(N as u32),
80	            &a_dev,
81	            &b_dev,
82	            &mut c_dev,
83	        )
84	        .expect("Kernel launch failed");
85	
86	    // Get results
87	    let c_host = c_dev.to_host_vec(&stream).unwrap();
88	
89	    println!("\nOutput vector (first 5 elements):");
90	    println!("  c = {:?}", &c_host[0..5]);
91	
92	    // Verify
93	    let mut errors = 0;
94	    for i in 0..N {
95	        let expected = a_host[i] + b_host[i];
96	        if (c_host[i] - expected).abs() > 1e-5 {
97	            if errors < 5 {
98	                eprintln!(
99	                    "  Error at [{}]: expected {}, got {}",
100	                    i, expected, c_host[i]
101	                );
102	            }
103	            errors += 1;
104	        }
105	    }
106	
107	    if errors == 0 {
108	        println!("\n✓ SUCCESS: All {} elements correct!", N);
109	    } else {
110	        println!("\n✗ FAILED: {} errors", errors);
111	        std::process::exit(1);
112	    }
113	}
