62	#[derive(Clone, Copy, Debug, PartialEq, Eq)]
63	enum SetDiscriminantLayout {
64	    Direct,
65	    Niche,
66	    Single { inhabited_variant: usize },
67	    Empty,
68	}
69	
70	#[derive(Clone, Copy, Debug, PartialEq, Eq)]
71	enum SetDiscriminantAction {
72	    WriteDirectTag,
73	    NoOp,
74	}
75	
76	#[derive(Clone, Copy, Debug, PartialEq, Eq)]
77	enum SetDiscriminantLayoutError {
78	    NicheEncoding,
79	    UninhabitedVariant,
80	}
