82	/// Decide whether `SetDiscriminant` writes a physical tag, does nothing, or
83	/// must be rejected. Keeping this decision separate from operation creation
84	/// makes every rustc enum layout explicit and independently testable.
85	fn classify_set_discriminant(
86	    layout: SetDiscriminantLayout,
87	    target_variant: usize,
88	    target_is_inhabited: bool,
89	) -> Result<SetDiscriminantAction, SetDiscriminantLayoutError> {
90	    match layout {
91	        SetDiscriminantLayout::Direct if target_is_inhabited => {
92	            Ok(SetDiscriminantAction::WriteDirectTag)
93	        }
94	        SetDiscriminantLayout::Direct | SetDiscriminantLayout::Empty => {
95	            Err(SetDiscriminantLayoutError::UninhabitedVariant)
96	        }
97	        SetDiscriminantLayout::Niche => Err(SetDiscriminantLayoutError::NicheEncoding),
98	        SetDiscriminantLayout::Single { inhabited_variant }
99	            if inhabited_variant == target_variant =>
100	        {
101	            Ok(SetDiscriminantAction::NoOp)
102	        }
103	        SetDiscriminantLayout::Single { .. } => Err(SetDiscriminantLayoutError::UninhabitedVariant),
104	    }
105	}
106	
107	/// rustc's direct-tag layout can still contain source variants that are
108	/// impossible to construct, such as `Dead(Never)`. The stable layout API does
109	/// not expose per-variant inhabitedness, so derive it from the monomorphized
110	/// ADT fields: a variant is uninhabited when any field has an empty layout.
111	fn adt_variant_is_inhabited(
112	    rust_ty: &rustc_public::ty::Ty,
113	    variant_index: usize,
114	    loc: Location,
115	) -> TranslationResult<bool> {
116	    let rustc_public::ty::TyKind::RigidTy(rustc_public::ty::RigidTy::Adt(adt, args)) =
117	        rust_ty.kind()
118	    else {
119	        // Compiler-generated enum-like types (for example coroutines) are not
120	        // ADTs. Their layout still identifies Single/Empty impossible cases;
121	        // direct layouts are trusted here and validated by type translation.
122	        return Ok(true);
123	    };
124	
125	    let index = rustc_public::ty::VariantIdx::to_val(variant_index);
126	    let variant = adt.variant(index).ok_or_else(|| {
127	        input_error!(
128	            loc.clone(),
129	            TranslationErr::unsupported(format!(
130	                "SetDiscriminant variant index {} is out of bounds",
131	                variant_index
132	            ))
133	        )
134	    })?;
135	
136	    for field in variant.fields() {
137	        let field_ty = field.ty_with_args(&args);
138	        let field_layout = field_ty.layout().map_err(|e| {
139	            input_error!(
140	                loc.clone(),
141	                TranslationErr::unsupported(format!(
142	                    "Failed to query SetDiscriminant target field layout: {:?}",
143	                    e
144	                ))
145	            )
146	        })?;
147	        if matches!(
148	            field_layout.shape().variants,
149	            rustc_public::abi::VariantsShape::Empty
150	        ) {
151	            return Ok(false);
152	        }
153	    }
154	
155	    Ok(true)
156	}
