158	/// Translates a MIR statement to one or more `dialect-mir` operations.
159	///
160	/// # Returns
161	///
162	/// The last inserted operation (for chaining), or `prev_op` if no ops were created.
163	/// For `Rvalue::Use`, no operation is created - just updates `value_map`.
164	pub fn translate_statement(
165	    ctx: &mut Context,
166	    body: &mir::Body,
167	    stmt: &mir::Statement,
168	    value_map: &mut ValueMap,
169	    block_ptr: Ptr<BasicBlock>,
170	    prev_op: Option<Ptr<Operation>>,
171	) -> TranslationResult<Option<Ptr<Operation>>> {
172	    let loc = span_to_location(ctx, stmt.span);
173	
174	    match &stmt.kind {
175	        mir::StatementKind::Assign(place, rvalue) => {
176	            // Fast paths: array initializers assigned to an addressable local.
177	            // Store each element directly into the alloca storage instead of
178	            // building an SSA aggregate (insertvalue chain) and then storing it.
179	            if value_map.get_slot(place.local).is_some() {
180	                match rvalue {
181	                    mir::Rvalue::Aggregate(mir::AggregateKind::Array(_), operands) => {
182	                        return translate_array_agg_into_alloca(
183	                            ctx, body, place, operands, value_map, block_ptr, prev_op, loc,
184	                        );
185	                    }
186	                    mir::Rvalue::Repeat(operand, count) => {
187	                        let n = count.eval_target_usize().map_err(|e| {
188	                            input_error!(
189	                                loc.clone(),
190	                                TranslationErr::unsupported(format!(
191	                                    "Failed to evaluate Repeat count: {:?}",
192	                                    e
193	                                ))
194	                            )
195	                        })? as usize;
196	                        return translate_repeat_into_alloca(
197	                            ctx, body, place, operand, n, value_map, block_ptr, prev_op, loc,
198	                        );
199	                    }
200	                    _ => {}
201	                }
202	            }
203	
204	            // Translate the Rvalue to get the value being assigned
205	            let (rvalue_op_opt, result_value, last_inserted) = rvalue::translate_rvalue(
206	                ctx,
207	                body,
208	                rvalue,
209	                value_map,
210	                block_ptr,
211	                prev_op,
212	                loc.clone(),
213	            )?;
214	
215	            // Map the result to the place (local variable)
216	            if place.projection.is_empty() {
217	                // Simple local assignment: write the rvalue into the local's
218	                // stack slot (`mir.store local_slot, value`). ZST locals
219	                // (no slot) are silently skipped -- nothing to materialise.
220	                let local = place.local;
221	
222	                // Insert the rvalue operation if it's not None
223	                // For Rvalue::Use, rvalue_op_opt is None (no operation to insert)
224	                // For other Rvalues (like CheckedAdd), we need to insert the operation
225	                let current_prev = if let Some(rvalue_op) = rvalue_op_opt {
226	                    if let Some(prev) = last_inserted {
227	                        rvalue_op.insert_after(ctx, prev);
228	                    } else if let Some(prev) = prev_op {
229	                        rvalue_op.insert_after(ctx, prev);
230	                    } else {
231	                        rvalue_op.insert_at_front(block_ptr, ctx);
232	                    }
233	                    Some(rvalue_op)
234	                } else {
235	                    // For Rvalue::Use, return the last inserted operation (field extraction if any)
236	                    // If last_inserted is None, we return prev_op
237	                    last_inserted.or(prev_op)
238	                };
239	
240	                let store_op =
241	                    value_map.store_local(ctx, local, result_value, block_ptr, current_prev);
242	                Ok(store_op.or(current_prev))
243	            } else if place.projection.len() == 1 {
244	                match &place.projection[0] {
245	                    mir::ProjectionElem::Deref => {
246	                        // *ptr = value (Store)
247	                        // Translate the pointer (base)
248	                        let base_place = mir::Place {
249	                            local: place.local,
250	                            projection: vec![],
251	                        };
252	
253	                        // Determine current_prev based on rvalue insertion
254	                        let mut current_prev = prev_op;
255	                        if let Some(rvalue_op) = rvalue_op_opt {
256	                            if let Some(prev) = last_inserted {
257	                                rvalue_op.insert_after(ctx, prev);
258	                                current_prev = Some(rvalue_op);
259	                            } else if let Some(prev) = prev_op {
260	                                rvalue_op.insert_after(ctx, prev);
261	                                current_prev = Some(rvalue_op);
262	                            } else {
263	                                rvalue_op.insert_at_front(block_ptr, ctx);
264	                                current_prev = Some(rvalue_op);
265	                            }
266	                        } else if let Some(prev) = last_inserted {
267	                            current_prev = Some(prev);
268	                        }
269	
270	                        // Re-translate place with updated prev_op to ensure ordering
271	                        let (ptr_val, prev_op_after_ptr) = rvalue::translate_place(
272	                            ctx,
273	                            body,
274	                            &base_place,
275	                            value_map,
276	                            block_ptr,
277	                            current_prev,
278	                            loc.clone(),
279	                        )?;
280	
281	                        // Create Store Op
282	                        let store_op = Operation::new(
283	                            ctx,
284	                            MirStoreOp::get_concrete_op_info(),
285	                            vec![],                      // No results
286	                            vec![ptr_val, result_value], // ptr, value
287	                            vec![],
288	                            0,
289	                        );
290	                        store_op.deref_mut(ctx).set_loc(loc);
291	
292	                        if let Some(prev) = prev_op_after_ptr {
293	                            store_op.insert_after(ctx, prev);
294	                        } else {
295	                            // This implies block was empty and both rvalue and place didn't insert ops?
296	                            // Or they inserted at front.
297	                            store_op.insert_at_front(block_ptr, ctx);
298	                        }
299	
300	                        Ok(Some(store_op))
301	                    }
302	                    mir::ProjectionElem::Field(field_idx, field_ty) => {
303	                        // struct.field = value (field assignment)
304	                        //
305	                        // Alloca model: compute the field's address from the
306	                        // local's slot via [`MirFieldAddrOp`] and store
307	                        // directly. This keeps the write addressable by
308	                        // `mem2reg` and avoids rebuilding the whole aggregate
309	                        // on every field update.
310	
311	                        let mut current_prev = prev_op;
312	                        if let Some(rvalue_op) = rvalue_op_opt {
313	                            if let Some(prev) = last_inserted {
314	                                rvalue_op.insert_after(ctx, prev);
315	                                current_prev = Some(rvalue_op);
316	                            } else if let Some(prev) = prev_op {
317	                                rvalue_op.insert_after(ctx, prev);
318	                                current_prev = Some(rvalue_op);
319	                            } else {
320	                                rvalue_op.insert_at_front(block_ptr, ctx);
321	                                current_prev = Some(rvalue_op);
322	                            }
323	                        } else if let Some(prev) = last_inserted {
324	                            current_prev = Some(prev);
325	                        }
326	
327	                        let local = place.local;
328	                        let Some(slot) = value_map.get_slot(local) else {
329	                            return input_err!(
330	                                loc,
331	                                TranslationErr::unsupported(format!(
332	                                    "Local {:?} has no alloca slot for field assignment",
333	                                    local
334	                                ))
335	                            );
336	                        };
337	
338	                        let field_type = types::translate_type(ctx, field_ty)?;
339	                        let slot_mutable = pointer_is_mutable(ctx, slot);
340	                        let field_ptr_ty = dialect_mir::types::MirPtrType::get(
341	                            ctx,
342	                            field_type,
343	                            slot_mutable,
344	                            pointer_address_space(ctx, slot),
345	                        )
346	                        .into();
347	
348	                        use dialect_mir::ops::MirFieldAddrOp;
349	                        let field_addr_op = Operation::new(
350	                            ctx,
351	                            MirFieldAddrOp::get_concrete_op_info(),
352	                            vec![field_ptr_ty],
353	                            vec![slot],
354	                            vec![],
355	                            0,
356	                        );
357	                        field_addr_op.deref_mut(ctx).set_loc(loc.clone());
358	                        MirFieldAddrOp::new(field_addr_op).set_attr_field_index(
359	                            ctx,
360	                            dialect_mir::attributes::FieldIndexAttr(*field_idx as u32),
361	                        );
362	                        if let Some(prev) = current_prev {
363	                            field_addr_op.insert_after(ctx, prev);
364	                        } else {
365	                            field_addr_op.insert_at_front(block_ptr, ctx);
366	                        }
367	                        let field_ptr = field_addr_op.deref(ctx).get_result(0);
368	
369	                        let store_op = Operation::new(
370	                            ctx,
371	                            MirStoreOp::get_concrete_op_info(),
372	                            vec![],
373	                            vec![field_ptr, result_value],
374	                            vec![],
375	                            0,
376	                        );
377	                        store_op.deref_mut(ctx).set_loc(loc);
378	                        store_op.insert_after(ctx, field_addr_op);
379	                        Ok(Some(store_op))
380	                    }
381	                    mir::ProjectionElem::ConstantIndex {
382	                        offset,
383	                        min_length: _,
384	                        from_end,
385	                    } => {
386	                        // arr[const_idx] = value.
387	                        //
388	                        // Alloca model: locate the element via
389	                        // `MirConstantOp` + `MirArrayElementAddrOp` from the
390	                        // local's slot and emit `mir.store`.
391	
392	                        if *from_end {
393	                            return input_err!(
394	                                loc,
395	                                TranslationErr::unsupported(
396	                                    "ConstantIndex with from_end=true not yet supported for writes"
397	                                )
398	                            );
399	                        }
400	
401	                        let mut current_prev = prev_op;
402	                        if let Some(rvalue_op) = rvalue_op_opt {
403	                            if let Some(prev) = last_inserted {
404	                                rvalue_op.insert_after(ctx, prev);
405	                                current_prev = Some(rvalue_op);
406	                            } else if let Some(prev) = prev_op {
407	                                rvalue_op.insert_after(ctx, prev);
408	                                current_prev = Some(rvalue_op);
409	                            } else {
410	                                rvalue_op.insert_at_front(block_ptr, ctx);
411	                                current_prev = Some(rvalue_op);
412	                            }
413	                        } else if let Some(prev) = last_inserted {
414	                            current_prev = Some(prev);
415	                        }
416	
417	                        let local = place.local;
418	                        let index = *offset as usize;
419	                        let Some(arr_ptr) = value_map.get_slot(local) else {
420	                            return input_err!(
421	                                loc,
422	                                TranslationErr::unsupported(format!(
423	                                    "Local {:?} has no alloca slot for array element assignment",
424	                                    local
425	                                ))
426	                            );
427	                        };
428	
429	                        let (element_ty, address_space) =
430	                            slot_array_element_ty(ctx, arr_ptr, &loc)?;
431	
432	                        use dialect_mir::ops::MirConstantOp;
433	                        use pliron::builtin::attributes::IntegerAttr;
434	
435	                        let i64_ty = IntegerType::get(ctx, 64, Signedness::Signed);
436	                        let index_apint =
437	                            APInt::from_i64(index as i64, NonZeroUsize::new(64).unwrap());
438	                        let index_attr = IntegerAttr::new(i64_ty, index_apint);
439	
440	                        let const_op_ptr = Operation::new(
441	                            ctx,
442	                            MirConstantOp::get_concrete_op_info(),
443	                            vec![i64_ty.into()],
444	                            vec![],
445	                            vec![],
446	                            0,
447	                        );
448	                        const_op_ptr.deref_mut(ctx).set_loc(loc.clone());
449	                        MirConstantOp::new(const_op_ptr).set_attr_value(ctx, index_attr);
450	
451	                        if let Some(prev) = current_prev {
452	                            const_op_ptr.insert_after(ctx, prev);
453	                        } else {
454	                            const_op_ptr.insert_at_front(block_ptr, ctx);
455	                        }
456	                        current_prev = Some(const_op_ptr);
457	                        let index_value = const_op_ptr.deref(ctx).get_result(0);
458	
459	                        let store_op = emit_array_element_store(
460	                            ctx,
461	                            arr_ptr,
462	                            index_value,
463	                            result_value,
464	                            element_ty,
465	                            address_space,
466	                            block_ptr,
467	                            current_prev,
468	                            loc,
469	                        );
470	                        Ok(Some(store_op))
471	                    }
472	                    mir::ProjectionElem::Index(index_local) => {
473	                        // arr[i] = value with runtime index.
474	                        //
475	                        // Alloca model: fetch the index (via `load_local`
476	                        // through translate_place), GEP from the array's
477	                        // slot, and `mir.store` the value.
478	
479	                        let mut current_prev = prev_op;
480	                        if let Some(rvalue_op) = rvalue_op_opt {
481	                            if let Some(prev) = last_inserted {
482	                                rvalue_op.insert_after(ctx, prev);
483	                                current_prev = Some(rvalue_op);
484	                            } else if let Some(prev) = prev_op {
485	                                rvalue_op.insert_after(ctx, prev);
486	                                current_prev = Some(rvalue_op);
487	                            } else {
488	                                rvalue_op.insert_at_front(block_ptr, ctx);
489	                                current_prev = Some(rvalue_op);
490	                            }
491	                        } else if let Some(prev) = last_inserted {
492	                            current_prev = Some(prev);
493	                        }
494	
495	                        let local = place.local;
496	                        let Some(arr_ptr) = value_map.get_slot(local) else {
497	                            return input_err!(
498	                                loc,
499	                                TranslationErr::unsupported(format!(
500	                                    "Local {:?} has no alloca slot for runtime index write",
501	                                    local
502	                                ))
503	                            );
504	                        };
505	
506	                        let index_place = mir::Place {
507	                            local: *index_local,
508	                            projection: vec![],
509	                        };
510	                        let (index_value, prev_op_after_index) = rvalue::translate_place(
511	                            ctx,
512	                            body,
513	                            &index_place,
514	                            value_map,
515	                            block_ptr,
516	                            current_prev,
517	                            loc.clone(),
518	                        )?;
519	                        current_prev = prev_op_after_index;
520	
521	                        let (element_ty, address_space) =
522	                            slot_array_element_ty(ctx, arr_ptr, &loc)?;
523	
524	                        let store_op = emit_array_element_store(
525	                            ctx,
526	                            arr_ptr,
527	                            index_value,
528	                            result_value,
529	                            element_ty,
530	                            address_space,
531	                            block_ptr,
532	                            current_prev,
533	                            loc,
534	                        );
535	                        Ok(Some(store_op))
536	                    }
537	                    _ => input_err!(
538	                        loc,
539	                        TranslationErr::unsupported(
540	                            "Assignments to projections other than Deref, Field, ConstantIndex, and Index not yet implemented"
541	                        )
542	                    ),
543	                }
544	            } else if place.projection.len() == 2 {
545	                // Handle 2-level projections
546	                match (&place.projection[0], &place.projection[1]) {
547	                    (
548	                        mir::ProjectionElem::Deref,
549	                        mir::ProjectionElem::Field(field_idx, field_ty),
550	                    ) => {
551	                        // `(*ptr).field = value`.
552	                        //
553	                        // Alloca model: compute the field's address with
