1167	/// Shared walk-and-store path for projected assignments: insert the pending
1168	/// rvalue op (if any), walk the FULL projection chain of `place` to a
1169	/// mutable destination address with the same place-address walker that
1170	/// `Rvalue::Ref` uses (`rvalue::translate_place_address`), then write
1171	/// `result_value` through it with a single `mir.store`.
1172	///
1173	/// Used by the dedicated `(*ptr)[i] = value` arm (thin `&mut [T; N]` and
1174	/// fat `&mut [T]` bases, issue #58) and by the generic fallback for 3+
1175	/// projection chains such as `(*iter).alive.start = value` from the
1176	/// `for x in arr` loop machinery (issue #138).
1177	///
1178	/// A punt from the walker is reported as an unsupported construct: the
1179	/// destination is written through, so falling back to a value copy would
1180	/// silently lose the write.
1181	#[allow(clippy::too_many_arguments)]
1182	fn store_through_place_address(
1183	    ctx: &mut Context,
1184	    body: &mir::Body,
1185	    value_map: &ValueMap,
1186	    place: &mir::Place,
1187	    result_value: Value,
1188	    rvalue_op_opt: Option<Ptr<Operation>>,
1189	    last_inserted: Option<Ptr<Operation>>,
1190	    prev_op: Option<Ptr<Operation>>,
1191	    block_ptr: Ptr<BasicBlock>,
1192	    loc: Location,
1193	) -> TranslationResult<Option<Ptr<Operation>>> {
1194	    let mut current_prev = prev_op;
1195	    if let Some(rvalue_op) = rvalue_op_opt {
1196	        if let Some(prev) = last_inserted {
1197	            rvalue_op.insert_after(ctx, prev);
1198	        } else if let Some(prev) = prev_op {
1199	            rvalue_op.insert_after(ctx, prev);
1200	        } else {
1201	            rvalue_op.insert_at_front(block_ptr, ctx);
1202	        }
1203	        current_prev = Some(rvalue_op);
1204	    } else if let Some(prev) = last_inserted {
1205	        current_prev = Some(prev);
1206	    }
1207	
1208	    // The destination is written through, so request a mutable address.
1209	    let walked = rvalue::translate_place_address(
1210	        ctx,
1211	        body,
1212	        value_map,
1213	        place,
1214	        /* is_mutable */ true,
1215	        block_ptr,
1216	        current_prev,
1217	        loc.clone(),
1218	    )?;
1219	    let Some((dest_addr, addr_prev)) = walked else {
1220	        // The walker punted (a projection it cannot turn into an address,
1221	        // or the local has no slot). Reject loudly instead of copying.
1222	        return input_err!(
1223	            loc,
1224	            TranslationErr::unsupported(format!(
1225	                "cannot compute the destination address for the assignment \
1226	                 (projections {:?})",
1227	                place.projection
1228	            ))
1229	        );
1230	    };
1231	    let current_prev = addr_prev.or(current_prev);
1232	
1233	    let store_op = Operation::new(
1234	        ctx,
1235	        MirStoreOp::get_concrete_op_info(),
1236	        vec![],
1237	        vec![dest_addr, result_value],
1238	        vec![],
1239	        0,
1240	    );
1241	    store_op.deref_mut(ctx).set_loc(loc);
1242	    match current_prev {
1243	        Some(prev) => store_op.insert_after(ctx, prev),
1244	        None => store_op.insert_at_front(block_ptr, ctx),
1245	    }
1246	    Ok(Some(store_op))
1247	}
1248	
1249	/// Extract the element type and address space from a pointer that points
1250	/// to an array.
1251	///
1252	/// Used by the statement-level element write helpers. Returns a structured
1253	/// error when the pointer's pointee isn't a [`MirArrayType`], which signals
1254	/// a structural mismatch (most likely the wrong MIR projection reaching
1255	/// this path).
1256	fn slot_array_element_ty(
1257	    ctx: &pliron::context::Context,
1258	    arr_ptr: Value,
1259	    loc: &Location,
1260	) -> TranslationResult<(pliron::r#type::TypeHandle, u32)> {
1261	    let arr_ptr_ty = arr_ptr.get_type(ctx);
1262	    let arr_ptr_ty_ref = arr_ptr_ty.deref(ctx);
1263	    let mir_ptr_ty = arr_ptr_ty_ref
1264	        .downcast_ref::<dialect_mir::types::MirPtrType>()
1265	        .ok_or_else(|| {
1266	            pliron::input_error!(
1267	                loc.clone(),
1268	                TranslationErr::unsupported("Array-index slot is not a MirPtrType")
1269	            )
1270	        })?;
1271	    let address_space = mir_ptr_ty.address_space;
1272	    let pointee_ref = mir_ptr_ty.pointee.deref(ctx);
1273	    let element_ty = pointee_ref
1274	        .downcast_ref::<dialect_mir::types::MirArrayType>()
1275	        .ok_or_else(|| {
1276	            pliron::input_error!(
1277	                loc.clone(),
1278	                TranslationErr::unsupported("Array-index slot pointee is not MirArrayType",)
1279	            )
1280	        })?
1281	        .element_type();
1282	    Ok((element_ty, address_space))
1283	}
1284	
1285	/// Emit `mir.array_element_addr` + `mir.store` to assign `value` into
1286	/// `array_ptr[index]`, returning the `mir.store` op.
1287	///
1288	/// The caller owns positioning (`prev_op`): we chain the address op after
1289	/// it, then chain the store after the address op.
1290	#[allow(clippy::too_many_arguments)]
1291	fn emit_array_element_store(
1292	    ctx: &mut pliron::context::Context,
1293	    array_ptr: Value,
1294	    index: Value,
1295	    value: Value,
1296	    element_ty: pliron::r#type::TypeHandle,
1297	    address_space: u32,
1298	    block_ptr: Ptr<BasicBlock>,
1299	    prev_op: Option<Ptr<Operation>>,
1300	    loc: Location,
1301	) -> Ptr<Operation> {
1302	    let elem_ptr_ty =
1303	        dialect_mir::types::MirPtrType::get(ctx, element_ty, true, address_space).into();
1304	
1305	    use dialect_mir::ops::MirArrayElementAddrOp;
1306	    let addr_op = Operation::new(
1307	        ctx,
1308	        MirArrayElementAddrOp::get_concrete_op_info(),
1309	        vec![elem_ptr_ty],
1310	        vec![array_ptr, index],
1311	        vec![],
1312	        0,
1313	    );
1314	    addr_op.deref_mut(ctx).set_loc(loc.clone());
1315	    match prev_op {
1316	        Some(prev) => addr_op.insert_after(ctx, prev),
1317	        None => addr_op.insert_at_front(block_ptr, ctx),
1318	    }
1319	    let elem_ptr = addr_op.deref(ctx).get_result(0);
1320	
1321	    let store_op = Operation::new(
1322	        ctx,
1323	        MirStoreOp::get_concrete_op_info(),
1324	        vec![],
1325	        vec![elem_ptr, value],
1326	        vec![],
1327	        0,
1328	    );
1329	    store_op.deref_mut(ctx).set_loc(loc);
1330	    store_op.insert_after(ctx, addr_op);
1331	    store_op
1332	}
1333	
1334	/// Return `true` if the pointer value's type is a mutable [`MirPtrType`].
1335	///
1336	/// Slots emitted by the entry-block alloca loop are always mutable, but
1337	/// callers of the statement module sometimes thread pointers coming from
1338	/// other sources (loads, field-addr ops, ...), which may be immutable.
1339	/// Derived addresses inherit the base pointer's mutability to keep pliron
1340	/// type checking consistent.
1341	fn pointer_is_mutable(ctx: &pliron::context::Context, ptr: Value) -> bool {
1342	    let ty = ptr.get_type(ctx);
1343	    let ty_ref = ty.deref(ctx);
1344	    ty_ref
1345	        .downcast_ref::<dialect_mir::types::MirPtrType>()
1346	        .is_some_and(|p| p.is_mutable)
1347	}
1348	
1349	/// Return the address space of a pointer value. Defaults to 0 (the generic
1350	/// address space) if the value is not a [`MirPtrType`].
1351	fn pointer_address_space(ctx: &pliron::context::Context, ptr: Value) -> u32 {
1352	    let ty = ptr.get_type(ctx);
1353	    let ty_ref = ty.deref(ctx);
1354	    ty_ref
1355	        .downcast_ref::<dialect_mir::types::MirPtrType>()
1356	        .map(|p| p.address_space)
1357	        .unwrap_or(0)
1358	}
1359	
1360	/// Assign an array aggregate element-by-element into addressable storage.
1361	///
1362	/// Handles `Rvalue::Repeat(operand, N)` assigned to an addressable local.
1363	///
1364	/// Translates the operand once and stores N copies directly into the alloca
1365	/// via ConstantIndex projections. Avoids building a full SSA aggregate and the
1366	/// resulting `insertvalue` chain in LLVM IR.
1367	fn translate_repeat_into_alloca(
1368	    ctx: &mut Context,
1369	    body: &mir::Body,
1370	    dest_place: &mir::Place,
1371	    operand: &mir::Operand,
1372	    count: usize,
1373	    value_map: &mut ValueMap,
1374	    block_ptr: Ptr<BasicBlock>,
1375	    prev_op: Option<Ptr<Operation>>,
1376	    loc: Location,
1377	) -> TranslationResult<Option<Ptr<Operation>>> {
1378	    let (elem_val, after_operand) = rvalue::translate_operand(
1379	        ctx,
1380	        body,
1381	        operand,
1382	        value_map,
1383	        block_ptr,
1384	        prev_op,
1385	        loc.clone(),
1386	    )?;
1387	    let mut current_prev = after_operand.or(prev_op);
1388	
1389	    for i in 0..count {
1390	        let elem_place = mir::Place {
1391	            local: dest_place.local,
1392	            projection: dest_place
1393	                .projection
1394	                .iter()
1395	                .cloned()
1396	                .chain(std::iter::once(mir::ProjectionElem::ConstantIndex {
1397	                    offset: i as u64,
1398	                    min_length: count as u64,
1399	                    from_end: false,
1400	                }))
1401	                .collect(),
1402	        };
1403	
1404	        let after_store = store_through_place_address(
1405	            ctx,
1406	            body,
1407	            value_map,
1408	            &elem_place,
1409	            elem_val,
1410	            None,
1411	            current_prev,
1412	            current_prev,
1413	            block_ptr,
1414	            loc.clone(),
1415	        )?;
1416	        current_prev = after_store.or(current_prev);
1417	    }
1418	
1419	    Ok(current_prev)
1420	}
1421	
1422	/// When the destination has an alloca slot and the RHS is
1423	/// `Rvalue::Aggregate(Array, operands)`, building a full SSA aggregate
1424	/// (`MirConstructArrayOp`) followed by a single large store produces a chain
1425	/// of `insertvalue` instructions in LLVM IR. This helper skips the aggregate
1426	/// entirely and stores each element directly to its computed address.
1427	fn translate_array_agg_into_alloca(
1428	    ctx: &mut Context,
1429	    body: &mir::Body,
1430	    dest_place: &mir::Place,
1431	    operands: &[mir::Operand],
1432	    value_map: &mut ValueMap,
1433	    block_ptr: Ptr<BasicBlock>,
1434	    prev_op: Option<Ptr<Operation>>,
1435	    loc: Location,
1436	) -> TranslationResult<Option<Ptr<Operation>>> {
1437	    let mut current_prev = prev_op;
1438	
1439	    for (i, operand) in operands.iter().enumerate() {
1440	        let (elem_val, after_operand) = rvalue::translate_operand(
1441	            ctx,
1442	            body,
1443	            operand,
1444	            value_map,
1445	            block_ptr,
1446	            current_prev,
1447	            loc.clone(),
1448	        )?;
1449	        current_prev = after_operand.or(current_prev);
1450	
1451	        // Extend the destination place with a ConstantIndex for this element.
1452	        let elem_place = mir::Place {
1453	            local: dest_place.local,
1454	            projection: dest_place
1455	                .projection
1456	                .iter()
1457	                .cloned()
1458	                .chain(std::iter::once(mir::ProjectionElem::ConstantIndex {
1459	                    offset: i as u64,
1460	                    min_length: operands.len() as u64,
1461	                    from_end: false,
1462	                }))
1463	                .collect(),
1464	        };
1465	
1466	        let after_store = store_through_place_address(
1467	            ctx,
1468	            body,
1469	            value_map,
1470	            &elem_place,
1471	            elem_val,
1472	            None,
1473	            current_prev,
1474	            current_prev,
1475	            block_ptr,
1476	            loc.clone(),
1477	        )?;
1478	        current_prev = after_store.or(current_prev);
1479	    }
1480	
1481	    Ok(current_prev)
1482	}
1483	
1484	#[cfg(test)]
1485	mod tests {
1486	    use super::*;
1487	
1488	    #[test]
1489	    fn set_discriminant_layout_actions_are_explicit() {
1490	        assert_eq!(
1491	            classify_set_discriminant(SetDiscriminantLayout::Direct, 2, true),
1492	            Ok(SetDiscriminantAction::WriteDirectTag)
1493	        );
1494	        assert_eq!(
1495	            classify_set_discriminant(SetDiscriminantLayout::Direct, 2, false),
1496	            Err(SetDiscriminantLayoutError::UninhabitedVariant)
1497	        );
1498	        assert_eq!(
1499	            classify_set_discriminant(SetDiscriminantLayout::Niche, 0, true),
1500	            Err(SetDiscriminantLayoutError::NicheEncoding)
1501	        );
1502	        assert_eq!(
1503	            classify_set_discriminant(
1504	                SetDiscriminantLayout::Single {
1505	                    inhabited_variant: 1,
1506	                },
1507	                1,
1508	                true,
1509	            ),
1510	            Ok(SetDiscriminantAction::NoOp)
1511	        );
1512	        assert_eq!(
1513	            classify_set_discriminant(
1514	                SetDiscriminantLayout::Single {
1515	                    inhabited_variant: 1,
1516	                },
1517	                0,
1518	                true,
1519	            ),
1520	            Err(SetDiscriminantLayoutError::UninhabitedVariant)
1521	        );
1522	        assert_eq!(
1523	            classify_set_discriminant(SetDiscriminantLayout::Empty, 0, false),
1524	            Err(SetDiscriminantLayoutError::UninhabitedVariant)
1525	        );
1526	    }
1527	}
